			function ( $user ) {
				$display_name = trim( (string) $user->display_name );

				if ( $display_name === '' ) {
					$display_name = $user->user_login;
				}

				return [
					'id'           => $user->user_id,
					'display_name' => $display_name,
					'user_email'   => $user->user_email,
					'avatar'       => get_avatar_url( $user->user_id ),
					'count'        => (int) $user->count,
				];
			},
			$users
		)

